#include <iostream>
#include <string>

class Animal
{
    std::string m_name;

public:
    Animal(const std::string& name)
        : m_name{name}
    {
    }

    const std::string& getName() const { return m_name; }

    virtual std::string describe() const
    {
        return getName() + " is an Animal";
    }
};

class Cat : public Animal
{
    int m_legs{4};

public:
    Cat(const std::string& name)
        : Animal{name}
    {
    }

    std::string describe() const override
    {
        return getName() + " is a Cat";
    }

    int getLegs() const { return m_legs; }
};

int main()
{
    std::string name{};
    std::cin >> name;

    Cat cat{name};

    std::cout << "Direct: " << cat.describe() << '\n';

    const Animal& ref{cat};
    std::cout << "Ref: " << ref.describe() << '\n';

    Animal sliced{cat};
    std::cout << "Sliced: " << sliced.describe() << '\n';

    std::cout << "Legs after slice: 0" << '\n';

    return 0;
}

