#include <iostream>
#include <string>
#include <vector>

constexpr double pi{3.14159265};

class Shape
{
public:
    virtual std::string label() const { return "Shape"; }
    virtual double area() const { return 0.0; }
};

class Circle : public Shape
{
    int m_radius{};

public:
    Circle(int radius)
        : m_radius{radius}
    {
    }

    std::string label() const override { return "Circle"; }
    double area() const override { return pi * m_radius * m_radius; }
};

class Rectangle : public Shape
{
    int m_width{};
    int m_height{};

public:
    Rectangle(int width, int height)
        : m_width{width}, m_height{height}
    {
    }

    std::string label() const override { return "Rect"; }
    double area() const override { return static_cast<double>(m_width) * m_height; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Shape*> shapes{};

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;

        if (type == "circle")
        {
            int r{};
            std::cin >> r;
            shapes.push_back(new Circle{r});
        }
        else
        {
            int w{}, h{};
            std::cin >> w >> h;
            shapes.push_back(new Rectangle{w, h});
        }
    }

    for (const auto* s : shapes)
    {
        std::cout << s->label() << ": " << static_cast<int>(s->area()) << '\n';
    }

    for (auto* s : shapes)
    {
        delete s;
    }

    return 0;
}
